var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"하아. 살 것 같다.","JPN":"はあ、生き返った気分。","ENG":"Whew, now we’re living.","TWN":"呼～舒服～"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"역시 한바탕 하고 나면 배고파진다니까.","JPN":"やっぱり一仕事した後は腹が減るね。","ENG":"I always get famished after a good tussle.","TWN":"運動後總是特別餓呢！"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뛰기 전엔 먹지도 못하고. 운동 끝나면 바로 달려가서 두 그릇씩 먹었었는데.","JPN":"走る前は食べられないからさ。トレーニングが終わってすぐ食堂まで走っていっておかわりして食べてたなあ。","ENG":"Since I couldn’t eat before running, I’d rush to get food and eat two servings right after practice.","TWN":"以前在跑步前都不能吃東西，我都會在運動完後立刻衝來狂吃兩大盤！"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"우리도 덩달아 많이 먹느라 살 꽤 쪘었지.","JPN":"ワタシたちもそれに釣られていっぱい食べてたら、かなり太っちゃった。","ENG":"Yeah, so we gained some weight from eating with you.","TWN":"我們陪你一起吃，結果就變胖啦。"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"즌쯔 므스써(진짜 맛있어).","JPN":"すんぐくういしい(すごくおいしい)。","ENG":"Thhs ithh rlly tsty (This is really tasty).","TWN":"好好粗！"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"으휴. 다 먹고 얘기해. 입가에 다 묻었네. 이리로 와 봐.","JPN":"はあ、ちゃんと飲み込んでからしゃべりなよ。口元に全部付いてるよ。ほら、こっち向いて。","ENG":"Eww. Talk after you finish eating. You’re gonna get food all over your mouth. Come here.","TWN":"真是的，嘴巴裡的東西吞下去再說話啦！你看你的嘴巴都沾到了，過來我幫你擦！"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"으응. 고마워, 도로시.","JPN":"うん。ありがとう、ドロシーちゃん。","ENG":"Yep. Thanks, Dorothy.","TWN":"嗯嗯，謝謝你，桃樂絲。"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"저건…… 괜찮은 건가? 표정이 안 좋은데?","JPN":"あれは……大丈夫？　機嫌が悪そうに見えるんだけど。","ENG":"Is that... okay? It looks upset.","TWN":"那個東西……還好吧？好像臉色不太好？"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"혹시 내가 자길 오해해서 기분이 나빴나……? 그런 거면 미안. 사과할게.","JPN":"もしかして私が君のことを誤解してたから、気を悪くしたのかな……？\\nならごめん。謝るよ。","ENG":"Is he upset that I misunderstood him? If that’s the case, I’m sorry. I apologize for earlier.","TWN":"是因為我誤會它，所以它心情不好嗎……？是的話我道歉，對不起！"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아냐, 도로시. 제대로 못 먹어서 그럴 거야. 감자튀김 주면 돼.","JPN":"違うよ、ドロシーちゃん。お腹が空いてるからだと思う。フライドポテトをあげればいいの。","ENG":"It’s okay, Dorothy. He’s just grumpy because he didn’t get to eat properly. I just need to give him some french fries.","TWN":"不是啦，桃樂絲。是因為它沒東西吃啦，只要把薯條給它就好。"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"휴. 정말 다행이지…….","JPN":"ふう。本当によかった……","ENG":"Whew, it’s really a relief though.","TWN":"呼～真是好險……"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"다행이라니?","JPN":"よかったって？","ENG":"A relief?","TWN":"什麼好險？"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"사람을 먹으면 그땐 돌이킬 수 없을 것 같아서…… 걱정했는데.","JPN":"人を食べたらもう取り返しがつかなくなると思って……ずっと心配してたの。","ENG":"I was worried that he would cross a point of no return if he ate people...","TWN":"我原本很擔心，萬一它真的吃人……事情會變得一發不可收拾。"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그, 그러게……. 꼭 편식하는 것처럼 다 뱉어내던데.","JPN":"そ、そうだね……まるで好き嫌いする子どもみたいに、全部吐き出してたね。","ENG":"Y-yeah... He seemed to spit them out as if he was a picky eater.","TWN":"就是說……不過它好像很挑嘴，還把他們都吐出來。"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"입맛이 바뀌었나? 맛있는 것만 준 게 효과가 있었나 봐.","JPN":"好みが変わったのかな？\\nおいしいものだけ食べさせてたのが効いたみたい。","ENG":"Are his preferences changed? Maybe feeding him only delicious things affected him.","TWN":"是它口味變了嗎？可能是我平時只餵它吃好吃的，所以變得挑嘴吧？"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>기생체</color> 주제에 그동안 호강했구나, 너?","JPN":"……君、<color=#ffd34c>寄生体</color>のくせにこれまで贅沢してきたのか？","ENG":"Even a <color=#ffd34c>parasite</color> like you got to live the high life, eh?","TWN":"……身為一個<color=#ffd34c>寄生物</color>，你倒是過得很爽嘛？"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"편식하는 <color=#ffd34c>기생체</color>라니. 주인처럼 허술한 면이 있네.","JPN":"好き嫌いする<color=#ffd34c>寄生体</color>だなんてね。抜けている面があるのは飼い主そっくりだな。","ENG":"A picky <color=#ffd34c>parasite</color>... Looks like both you and your owner have a quirky side.","TWN":"<color=#ffd34c>寄生物</color>還挑食，看來你跟你主人一樣，都有點難搞！"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아니, 주인이라고 할 수 있나? <color=#ffd34c>기생체</color>니까 얘가 주인이고, 네가 숙주……","JPN":"いや、主って言っていいのかな？　<color=#ffd34c>寄生体</color>だからこの子が主で、君が宿主……","ENG":"Now that I mention it, can I even call you the owner? Since he’s a <color=#ffd34c>parasite</color>, he’s the owner and you’re the host...","TWN":"不對，可以算是主人嗎？它是<color=#ffd34c>寄生物</color>，那應該它才是主人，而你是宿主……"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OZ_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};